import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - nextGeneration", () => {
  it.todo("should return empty array for empty input");
  it.todo("should kill a single live cell with no neighbors (underpopulation)");
  it.todo("should kill two adjacent live cells (each has only 1 neighbor - underpopulation)");
  it.todo("should keep a block still-life unchanged (each cell has 3 neighbors)");
  it.todo("should oscillate a horizontal blinker into a vertical blinker");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should support negative coordinates on the infinite grid");
});
